--
-- Name: check_kudos_limits(character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_kudos_limits(p_giver_id character varying, p_recipient_id character varying) RETURNS character varying
    LANGUAGE sql
    AS $$
    SELECT CASE
        WHEN p_giver_id = p_recipient_id
            THEN 'You can''t give kudos to yourself!'
        WHEN EXISTS(SELECT 1 FROM kudos
            WHERE giver_id = p_giver_id AND created_at >= CURRENT_DATE)
            THEN 'You''ve already given kudos today. Try again tomorrow!'
        WHEN EXISTS(SELECT 1 FROM kudos
            WHERE giver_id = p_giver_id AND recipient_id = p_recipient_id
            AND created_at >= date_trunc('month', CURRENT_DATE))
            THEN 'You''ve already given kudos to this person this month.'
    END;
$$;


--
-- Name: delete_kudos(character varying, character varying); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.delete_kudos(IN p_channel_id character varying, IN p_message_ts character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
    PERFORM pg_advisory_xact_lock(hashtext('try_redeem'));
    UPDATE kudos SET redeemed_at = NULL, overflow = FALSE
    WHERE id IN (SELECT redeems FROM kudos WHERE channel_id = p_channel_id AND message_ts = p_message_ts AND redeems IS NOT NULL);
    DELETE FROM kudos WHERE channel_id = p_channel_id AND message_ts = p_message_ts;
    PERFORM try_redeem();
END;
$$;


--
-- Name: effective_budget(date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.effective_budget(p_as_of date DEFAULT CURRENT_DATE) RETURNS TABLE(conversion_rate numeric, point_budget integer)
    LANGUAGE sql STABLE
    AS $$
    (SELECT b.conversion_rate, b.point_budget FROM budgets b
    WHERE b.month_date <= p_as_of
    ORDER BY b.month_date DESC)
    UNION ALL (SELECT 1, 0) LIMIT 1;
$$;


--
-- Name: give_kudos(character varying, character varying, character varying, character varying, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.give_kudos(p_giver_id character varying, p_recipient_id character varying, p_channel_id character varying, p_message_ts character varying, p_message_text text DEFAULT NULL::text) RETURNS TABLE(error character varying, conversion_rate numeric, redeemed_user_ids character varying[], notify_budget_exhausted boolean)
    LANGUAGE plpgsql
    AS $$
DECLARE v_error VARCHAR(128);
BEGIN
    PERFORM pg_advisory_xact_lock(hashtext('try_redeem'));
    v_error := check_kudos_limits(p_giver_id, p_recipient_id);
    IF v_error IS NOT NULL THEN
        RETURN QUERY SELECT v_error, NULL::NUMERIC, '{}'::VARCHAR[], FALSE;
        RETURN;
    END IF;
    VALUES (p_giver_id, p_recipient_id, p_channel_id, p_message_ts, p_message_text)
    ON CONFLICT (channel_id, message_ts) DO NOTHING;
    IF NOT FOUND THEN RETURN; END IF;
    RETURN QUERY
    SELECT NULL::VARCHAR,
        b.conversion_rate,
        r.redeemed_user_ids,
        r.notify_budget_exhausted
    FROM try_redeem() r, effective_budget() b;
END;
$$;


--
-- Name: redeemed_this_month(date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.redeemed_this_month(p_month date DEFAULT (date_trunc('month'::text, (CURRENT_DATE)::timestamp with time zone))::date) RETURNS integer
    LANGUAGE sql STABLE
    AS $$
    SELECT COUNT(*)::int FROM kudos
    WHERE redeemed_at >= p_month
      AND redeemed_at < p_month + INTERVAL '1 month'
      AND NOT overflow;
$$;


--
-- Name: remaining_budget(date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.remaining_budget(p_as_of date DEFAULT CURRENT_DATE) RETURNS integer
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    RETURN (SELECT GREATEST(0, b.point_budget - redeemed_this_month(date_trunc('month', p_as_of)::date))::int
            FROM effective_budget(p_as_of) b);
END;
$$;


--
-- Name: try_redeem(timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.try_redeem(p_as_of timestamp with time zone DEFAULT now()) RETURNS TABLE(redeemed_user_ids character varying[], notify_budget_exhausted boolean)
    LANGUAGE plpgsql
    AS $$
DECLARE v_remaining INTEGER;
BEGIN
    PERFORM pg_advisory_xact_lock(hashtext('try_redeem'));  -- reentrant if caller already holds it
    v_remaining := remaining_budget(p_as_of::date);
    RETURN QUERY
    WITH pairs AS (
        SELECT rn, give_id, receive_id FROM to_redeem
    ),
    redeemed AS (
        UPDATE kudos SET redeemed_at = p_as_of, overflow = pairs.rn > v_remaining
        FROM pairs
        WHERE kudos.id = pairs.receive_id
        RETURNING recipient_id
    ),
    linked AS (
        UPDATE kudos SET redeems = p.receive_id
        FROM pairs p WHERE kudos.id = p.give_id AND p.rn <= v_remaining
    )
    SELECT
        COALESCE(array_agg(DISTINCT recipient_id), '{}'),
        count(*) >= v_remaining AND v_remaining > 0
    FROM redeemed;
END;
$$;


