--
-- Name: current_month_redemptions; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.current_month_redemptions AS
 SELECT k.recipient_id,
    array_agg(k.channel_id) AS channels,
    array_agg(k.message_ts) AS timestamps,
    ((count(*))::numeric * b.conversion_rate) AS total
   FROM public.kudos k,
    public.effective_budget() b(conversion_rate, point_budget)
  WHERE ((k.redeemed_at >= date_trunc('month'::text, (CURRENT_DATE)::timestamp with time zone)) AND (NOT k.overflow))
  GROUP BY k.recipient_id, b.conversion_rate;


