--

CREATE VIEW public.kudos_messages AS
 SELECT k.id,
    k.giver_id,
    k.recipient_id,
    ug.display_name AS giver,
    ur.display_name AS recipient,
    k.message_text AS message,
    (k.created_at)::date AS date,
    to_char(k.created_at, 'YYYY-MM'::text) AS month
   FROM ((public.kudos k
     JOIN public.users ug ON (((ug.id)::text = (k.giver_id)::text)))
     JOIN public.users ur ON (((ur.id)::text = (k.recipient_id)::text)));


--
-- Name: leaderboard; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.leaderboard AS
 SELECT u.display_name,
    (sum(exp((('-0.693'::numeric * EXTRACT(epoch FROM (now() - k.created_at))) / ((30 * 86400))::numeric))))::numeric(10,1) AS received
   FROM (public.kudos k
     JOIN public.users u ON (((u.id)::text = (k.recipient_id)::text)))
  GROUP BY u.id, u.display_name
  ORDER BY ((sum(exp((('-0.693'::numeric * EXTRACT(epoch FROM (now() - k.created_at))) / ((30 * 86400))::numeric))))::numeric(10,1)) DESC
 LIMIT 25;


--
-- Name: to_redeem; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.to_redeem AS
 WITH gives AS (
         SELECT kudos.id,
            kudos.giver_id,
            row_number() OVER (PARTITION BY kudos.giver_id ORDER BY kudos.created_at, kudos.id) AS rn
           FROM public.kudos
          WHERE (kudos.redeems IS NULL)
        ), receives AS (
         SELECT kudos.id,
            kudos.recipient_id,
            row_number() OVER (PARTITION BY kudos.recipient_id ORDER BY kudos.created_at, kudos.id) AS rn
           FROM public.kudos
          WHERE ((kudos.redeemed_at IS NULL) AND (NOT kudos.overflow))
        )
 SELECT gives.id AS give_id,
    receives.id AS receive_id,
    row_number() OVER (ORDER BY gives.id) AS rn
   FROM (gives
     JOIN receives ON ((((gives.giver_id)::text = (receives.recipient_id)::text) AND (gives.rn = receives.rn))));


--
-- Name: topic_stream; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.topic_stream AS
 SELECT month,
    cluster_id,
    summary,
    frac
   FROM ( SELECT to_char(k.created_at, 'YYYY-MM'::text) AS month,
            c.id AS cluster_id,
            c.summary,
            ((count(*))::double precision / (sum(count(*)) OVER (PARTITION BY (to_char(k.created_at, 'YYYY-MM'::text))))::double precision) AS frac
           FROM ((public.kudos k
             JOIN public.cluster_members cm ON ((cm.kudos_id = k.id)))
             JOIN public.clusters c ON ((c.id = cm.cluster_id)))
          GROUP BY (to_char(k.created_at, 'YYYY-MM'::text)), c.id, c.summary) t
  WHERE (frac >= (0.1)::double precision)
  ORDER BY month, summary;


--
-- Name: weekly_kudos; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.weekly_kudos AS
 SELECT w.yw,
    w.ym,
    w.acquired,
    w.redeemed,
    b.point_budget,
    b.conversion_rate
   FROM (( SELECT to_char(k.created_at, 'IYYY-IW'::text) AS yw,
            to_char((((date_trunc('week'::text, min(k.created_at)))::date + 3))::timestamp with time zone, 'YYYY-MM'::text) AS ym,
            (count(*))::integer AS acquired,
            (count(*) FILTER (WHERE (k.redeems IS NOT NULL)))::integer AS redeemed
           FROM public.kudos k
          GROUP BY (to_char(k.created_at, 'IYYY-IW'::text))) w
     JOIN LATERAL public.effective_budget(((w.ym || '-01'::text))::date) b(conversion_rate, point_budget) ON (true))
  ORDER BY w.yw;


